//! Consensus analysis for multiblock datasets
//!
//! This module implements consensus analysis methods for multiblock data,
//! particularly Consensus PCA (CPCA) which finds common principal components
//! across multiple data blocks.
//!
//! # R Equivalents
//! - `consensus_pca()` - Main consensus analysis function
//! - `consensus_weights()` - Compute block weights for consensus
//! - `consensus_scores()` - Extract consensus scores

use crate::{
    common_types::{Matrix, Vector},
    errors::MultivarError,
    pca::PCA,
    preprocessing::{Preprocessor, Pipeline},
    projector::{BiProjector, Project, Reconstruct},
    svd::{SvdMethod, SvdResult},
};
use ndarray::{Array1, Array2, Axis};
use std::collections::HashMap;

/// Configuration for consensus analysis
#[derive(Debug, Clone)]
pub struct ConsensusConfig {
    /// Number of consensus components to extract
    pub n_components: Option<usize>,
    /// SVD method to use
    pub svd_method: SvdMethod,
    /// Whether to center blocks before analysis
    pub center: bool,
    /// Whether to scale blocks before analysis
    pub scale: bool,
    /// Maximum iterations for consensus weight optimization
    pub max_iterations: usize,
    /// Convergence tolerance
    pub tolerance: f64,
}

impl Default for ConsensusConfig {
    fn default() -> Self {
        Self {
            n_components: None,
            svd_method: SvdMethod::Full,
            center: true,
            scale: false,
            max_iterations: 100,
            tolerance: 1e-6,
        }
    }
}

/// Consensus projector for multiblock analysis
///
/// Implements Consensus PCA which finds common principal components
/// across multiple data blocks by iteratively optimizing block weights
/// to maximize consensus.
#[derive(Debug, Clone)]
pub struct ConsensusProjector {
    /// Global consensus model (BiProjector)
    global_model: BiProjector,
    /// Block-specific projectors
    block_models: HashMap<String, BiProjector>,
    /// Block weights (normalized to sum to 1)
    block_weights: HashMap<String, f64>,
    /// Preprocessing pipelines for each block
    preprocessors: HashMap<String, Pipeline>,
    /// Configuration
    config: ConsensusConfig,
    /// Number of iterations used
    iterations_used: usize,
    /// Convergence history
    convergence_history: Vec<f64>,
}

impl ConsensusProjector {
    /// Create a new consensus projector from multiple data blocks
    pub fn new(
        blocks: &HashMap<String, Matrix>,
        config: ConsensusConfig,
    ) -> Result<Self, MultivarError> {
        // Validate inputs
        if blocks.is_empty() {
            return Err(MultivarError::InvalidParameter(
                "At least one block required for consensus analysis".to_string(),
            ));
        }

        // Check that all blocks have the same number of rows
        let n_rows = blocks.values().next().unwrap().nrows();
        for (name, block) in blocks {
            if block.nrows() != n_rows {
                return Err(MultivarError::DimensionMismatch(format!(
                    "Block '{}' has {} rows, expected {}",
                    name,
                    block.nrows(),
                    n_rows
                )));
            }
        }

        // Initialize equal weights
        let n_blocks = blocks.len();
        let initial_weight = 1.0 / n_blocks as f64;
        let mut block_weights = HashMap::new();
        for name in blocks.keys() {
            block_weights.insert(name.clone(), initial_weight);
        }

        // Create preprocessors for each block
        let mut preprocessors = HashMap::new();
        for name in blocks.keys() {
            let mut pipeline = Pipeline::new();
            if config.center {
                pipeline = pipeline.add(Box::new(crate::preprocessing::Center::new(Axis(0))));
            }
            if config.scale {
                pipeline = pipeline.add(Box::new(crate::preprocessing::Scale::new(Axis(0))));
            }
            preprocessors.insert(name.clone(), pipeline);
        }

        // Create initial global model
        let concatenated = concatenate_blocks(blocks, &block_weights)?;
        let pca = PCA::fit(&concatenated, config.n_components, config.svd_method.clone())?;
        let global_model = pca.as_bi_projector();

        // Initialize with empty block models
        let block_models = HashMap::new();

        let mut projector = Self {
            global_model,
            block_models,
            block_weights,
            preprocessors,
            config,
            iterations_used: 0,
            convergence_history: Vec::new(),
        };

        // Fit the consensus model
        projector.fit(blocks)?;

        Ok(projector)
    }

    /// Fit the consensus model by iteratively optimizing block weights
    pub fn fit(&mut self, blocks: &HashMap<String, Matrix>) -> Result<(), MultivarError> {
        // Preprocess blocks
        let mut preprocessed_blocks = HashMap::new();
        for (name, block) in blocks {
            let pipeline = self.preprocessors.get_mut(name).unwrap();
            let preprocessed = pipeline.fit_transform(block)?;
            preprocessed_blocks.insert(name.clone(), preprocessed);
        }

        // Iterative consensus optimization
        let mut prev_weights = self.block_weights.clone();

        for iter in 0..self.config.max_iterations {
            // Step 1: Update global model using current weights
            let concatenated = concatenate_blocks(&preprocessed_blocks, &self.block_weights)?;
            let pca = PCA::fit(&concatenated, self.config.n_components, self.config.svd_method.clone())?;
            self.global_model = pca.as_bi_projector();

            // Step 2: Fit block-specific models
            self.block_models.clear();
            for (name, block) in &preprocessed_blocks {
                let block_pca = PCA::fit(block, self.config.n_components, self.config.svd_method.clone())?;
                self.block_models.insert(name.clone(), block_pca.as_bi_projector());
            }

            // Step 3: Update block weights based on similarity to global model
            let new_weights = self.compute_consensus_weights(&preprocessed_blocks)?;

            // Check convergence
            let weight_change = compute_weight_change(&prev_weights, &new_weights);
            self.convergence_history.push(weight_change);

            if weight_change < self.config.tolerance {
                self.iterations_used = iter + 1;
                self.block_weights = new_weights;
                break;
            }

            prev_weights = new_weights.clone();
            self.block_weights = new_weights;
        }

        if self.iterations_used == 0 {
            self.iterations_used = self.config.max_iterations;
        }

        Ok(())
    }

    /// Compute consensus weights based on similarity to global model
    fn compute_consensus_weights(
        &self,
        blocks: &HashMap<String, Matrix>,
    ) -> Result<HashMap<String, f64>, MultivarError> {
        let mut weights = HashMap::new();
        let mut total_similarity = 0.0;

        // Compute similarity of each block's loadings to global loadings
        let global_loadings = &self.global_model.v;

        for (name, _) in blocks {
            if let Some(block_model) = self.block_models.get(name) {
                let block_loadings = &block_model.v;

                // Compute RV coefficient (matrix correlation)
                let similarity = compute_rv_coefficient(global_loadings, block_loadings)?;
                weights.insert(name.clone(), similarity);
                total_similarity += similarity;
            }
        }

        // Normalize weights to sum to 1
        if total_similarity > 0.0 {
            for weight in weights.values_mut() {
                *weight /= total_similarity;
            }
        }

        Ok(weights)
    }

    /// Get consensus scores (from global model)
    pub fn consensus_scores(&self) -> &Matrix {
        self.global_model.scores()
    }

    /// Get consensus loadings (from global model)
    pub fn consensus_loadings(&self) -> &Matrix {
        self.global_model.components()
    }

    /// Get block-specific scores
    pub fn block_scores(&self, block_name: &str) -> Option<&Matrix> {
        self.block_models.get(block_name).map(|m| m.scores())
    }

    /// Get block weights
    pub fn block_weights(&self) -> &HashMap<String, f64> {
        &self.block_weights
    }

    /// Get number of iterations used
    pub fn iterations_used(&self) -> usize {
        self.iterations_used
    }

    /// Get convergence history
    pub fn convergence_history(&self) -> &[f64] {
        &self.convergence_history
    }
}

/// Concatenate blocks with optional weighting
fn concatenate_blocks(
    blocks: &HashMap<String, Matrix>,
    weights: &HashMap<String, f64>,
) -> Result<Matrix, MultivarError> {
    let mut columns = Vec::new();

    // Sort blocks by name for consistent ordering
    let mut block_names: Vec<_> = blocks.keys().cloned().collect();
    block_names.sort();

    for name in block_names {
        if let Some(block) = blocks.get(&name) {
            let weight = weights.get(&name).unwrap_or(&1.0);

            // Apply square root of weight to columns (so that squared values give the weight)
            let weighted_block = block * weight.sqrt();

            for col in weighted_block.axis_iter(Axis(1)) {
                columns.push(col.to_owned());
            }
        }
    }

    if columns.is_empty() {
        return Err(MultivarError::InvalidParameter(
            "No columns to concatenate".to_string(),
        ));
    }

    // Stack columns horizontally
    let n_rows = columns[0].len();
    let n_cols = columns.len();
    let mut result = Array2::zeros((n_rows, n_cols));

    for (i, col) in columns.into_iter().enumerate() {
        result.column_mut(i).assign(&col);
    }

    Ok(result)
}

/// Compute RV coefficient between two matrices (matrix correlation)
fn compute_rv_coefficient(x: &Matrix, y: &Matrix) -> Result<f64, MultivarError> {
    if x.nrows() != y.nrows() {
        return Err(MultivarError::DimensionMismatch(
            "Matrices must have same number of rows for RV coefficient".to_string(),
        ));
    }

    // RV = trace(X'X * Y'Y) / sqrt(trace((X'X)^2) * trace((Y'Y)^2))
    let xx = x.t().dot(x);
    let yy = y.t().dot(y);
    let xy = xx.dot(&yy);

    let numerator = xy.diag().sum();
    let xx_squared = xx.dot(&xx);
    let yy_squared = yy.dot(&yy);

    let denominator = (xx_squared.diag().sum() * yy_squared.diag().sum()).sqrt();

    if denominator > 0.0 {
        Ok(numerator / denominator)
    } else {
        Ok(0.0)
    }
}

/// Compute change in weights between iterations
fn compute_weight_change(
    old_weights: &HashMap<String, f64>,
    new_weights: &HashMap<String, f64>,
) -> f64 {
    let mut total_change = 0.0;

    for (name, &new_weight) in new_weights {
        if let Some(&old_weight) = old_weights.get(name) {
            total_change += (new_weight - old_weight).abs();
        }
    }

    total_change
}

impl Project for ConsensusProjector {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivarError> {
        self.global_model.project(data)
    }
}

impl Reconstruct for ConsensusProjector {
    fn reconstruct(&self, scores: &Matrix) -> Result<Matrix, MultivarError> {
        self.global_model.reconstruct(scores)
    }
}

/// Result of consensus analysis
#[derive(Debug, Clone)]
pub struct ConsensusResult {
    /// The consensus projector
    pub projector: ConsensusProjector,
    /// Cross-block correlation matrix
    pub cross_correlations: Matrix,
    /// Consensus statistics per component
    pub consensus_stats: Vec<ConsensusStatistic>,
}

/// Statistics for a single consensus component
#[derive(Debug, Clone)]
pub struct ConsensusStatistic {
    /// Component index
    pub component: usize,
